"""
Gemini Client - Gemini 3 Pro Support
"""

import os
import google.generativeai as genai
from google.generativeai.types import HarmCategory, HarmBlockThreshold

class GeminiClient:
    """Client for Gemini 3 Pro with extended thinking and JSON mode."""

    def __init__(self, api_key: str = None, model_name: str = "gemini-3-pro-preview"):
        self.api_key = api_key or os.getenv("GEMINI_API_KEY")
        if not self.api_key:
            raise ValueError("GEMINI_API_KEY not found")

        genai.configure(api_key=self.api_key)
        self.model_name = model_name
        self.model = genai.GenerativeModel(model_name)

        self.safety_settings = {
            HarmCategory.HARM_CATEGORY_HARASSMENT: HarmBlockThreshold.BLOCK_NONE,
            HarmCategory.HARM_CATEGORY_HATE_SPEECH: HarmBlockThreshold.BLOCK_NONE,
            HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT: HarmBlockThreshold.BLOCK_NONE,
            HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT: HarmBlockThreshold.BLOCK_NONE,
        }

    def generate(self, prompt: str, temperature: float = 0.7, json_mode: bool = False) -> str:
        """Generate content with optional JSON mode."""

        generation_config = {
            "temperature": temperature,
            "top_p": 0.95,
            "top_k": 64,
            "max_output_tokens": 8192,
        }

        if json_mode:
            generation_config["response_mime_type"] = "application/json"

        try:
            response = self.model.generate_content(
                prompt,
                generation_config=generation_config,
                safety_settings=self.safety_settings
            )
            return response.text
        except Exception as e:
            print(f"Gemini Error: {e}")
            return ""

    def generate_with_thinking(self, prompt: str) -> str:
        """Generate content using extended thinking (simulated via prompt engineering for now)."""
        thinking_prompt = f"""
        Think step-by-step about the following request.
        Analyze the requirements, consider edge cases, and plan your response.

        Request: {prompt}
        """
        return self.generate(thinking_prompt, temperature=0.8)

